use hex;

use iso_8583_message::IsoMessage;

/*
"0":"0100",
"3":"000000",
"4":"000000000000",
"6":"000000000000",
"7":"0929135455",
"10":"61000000",
"11":"012597",
"12":"085455",
"13":"0929",
"14":"2510",
"15":"0929",
"16":"0928",
"18":"5812",
"22":"000",
"32":"999681",
"37":"080006500101",
"42":"F-5812-CAN     ",
"48":"F",
"49":"124",
"51":"124",
"61":"000000800080012490210",
"63":"MCSRM64GE"
*/
#[test]
fn standard_authorization() {
    let hex_string = "";
    let buffer = hex::decode(hex_string).unwrap();

    let iso_message = IsoMessage::from_buffer(buffer.clone()).unwrap();

    println!("{:?}", iso_message.get_message_map());

    let new_buffer = iso_message.get_message_buffer().unwrap();

    assert_eq!(buffer, new_buffer);
}

#[test]
fn more_complicated_authorization() {
    let hex_string = "";
    let buffer = hex::decode(hex_string).unwrap();

    let iso_message = IsoMessage::from_buffer(buffer.clone()).unwrap();

    println!("{:?}", iso_message.get_message_map());

    let new_buffer = iso_message.get_message_buffer().unwrap();

    assert_eq!(buffer, new_buffer);
}
